INSERT INTO days(user_id, day_number, diet_adhered, outdoor_workout_completed, indoor_workout_completed, water_consumed, pages_read, mood_rating, achievements, challenges, next_day_focus, progress_pic_key, created_at)
VALUES
  ('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 1, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Completed first day strong. Stuck to meal prep and both workouts.', 'Morning workout felt rough. Body not used to early wake-ups.', 'Set alarm 15 minutes earlier to give more transition time.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-01 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 2, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Hit water goal before 6pm for the first time. Reading felt enjoyable.', 'Diet slipped slightly at lunch - chose a smaller portion than planned.', 'Prep lunch the night before to avoid guessing.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-02 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 3, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Kept indoor workout session going despite low energy.', 'Rain cancelled outdoor walk. Felt guilty about missing it.', 'Check weather the night before and have a backup outdoor plan.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-03 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 4, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Best day so far. Energy was high all day. Outdoor run felt effortless.', 'Almost skipped reading due to tiredness but pushed through.', 'Use the high-energy days to build momentum, not coast.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-04 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 5, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Five days straight. Diet fully on track. Morning run was peaceful.', 'Social event made sticking to diet awkward.', 'Plan what to eat before going out next time.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-05 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 6, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Both workouts done despite diet slip. Reading streak intact.', 'Diet failed at dinner - gave in to takeaway after a long day.', 'Cook a batch of emergency meals for busy nights.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-06 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 7, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Full week complete. Recovered from yesterday. Feeling more disciplined.', 'Week fatigue hit hard in the afternoon. Almost skipped indoor workout.', 'Schedule indoor workout in the morning on Sundays.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-07 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 8, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Noticed clothes fitting slightly better. Motivation boosted.', 'Hard to focus on reading - mind kept wandering to work stress.', 'Try reading earlier in the day when focus is sharper.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-08 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 9, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Outdoor workout was long and felt really good. Diet clean all day.', 'Work ran late - missed indoor workout entirely.', 'Block workout time in calendar so work cannot override it.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-09 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 10, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 10 milestone. Feeling strong. Took first progress photo mentally.', 'Nothing major. This was a good day.', 'Keep this energy going into the second week.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-10 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 11, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Woke up without an alarm. Body is adjusting to the routine.', 'Cravings hit hard after dinner. Stayed strong.', 'Keep sugar-free snacks available for cravings.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-11 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 12, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Indoor workout was intense. Reading chapter was gripping.', 'Skipped outdoor workout - felt too exhausted from poor sleep.', 'Prioritise sleep. 7 hours minimum.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-12 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 13, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Two weeks almost done. Body feels leaner. Mindset sharper.', 'Social pressure to drink at a gathering. Declined.', 'Have a confident response ready when people push about drinking.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-13 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 14, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Two full weeks. Visibly more defined. Sleep quality improved hugely.', 'Minor knee discomfort on run. Slowed pace.', 'Add stretching routine before outdoor workouts.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-14 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 15, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Halfway to bronze. Consistency is becoming second nature.', 'Hunger was intense today - may need to adjust macros.', 'Research whether calorie intake needs to increase on high-output days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-15 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 16, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Outdoor run in the rain. Felt tough but empowering.', 'Getting bored of meal options. Need more variety.', 'Find five new compliant recipes this week.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-16 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 17, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Got through a tough mental day without breaking the streak.', 'Low mood made everything harder. Still completed all tasks.', 'On low-mood days, start with the smallest task first to build momentum.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-17 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 18, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Both workouts completed. Water and reading done.', 'Diet fell apart at lunch meeting - no good options available.', 'Always carry a compliant snack to meetings.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-18 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 19, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Strong recovery day after yesterday slip. Back fully on track.', 'Felt shame about yesterday. Had to push through mental resistance.', 'Separate identity from a single bad day. One slip is not failure.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-19 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 20, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Twenty days done. Visible muscle definition. Running pace faster.', 'Almost nothing. This was one of the best days yet.', 'Use this benchmark day as a reference on hard days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-20 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 21, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Three weeks in. Habit feels automatic now. Less mental effort required.', 'Restless sleep. Workouts felt sluggish.', 'Reduce screen time after 9pm to improve sleep.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-21 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 22, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Morning energy levels noticeably higher than week one.', 'Work deadline caused stress eating urge. Resisted.', 'Walk outside briefly when work stress spikes.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-22 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 23, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Indoor workout especially focused today. Diet perfect.', 'Outdoor workout skipped due to severe weather warning.', 'Accept weather as uncontrollable. Focus on what is within control.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-23 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 24, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'One day from bronze. Feeling proud and motivated.', 'Mild anxiety about hitting the 25-day mark - fear of losing momentum after.', 'Remind myself that 25 is a waypoint, not a finish line.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-24 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 25, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'BRONZE MILESTONE. 25 days complete. Body and mind transformed so far.', 'Temptation to celebrate with a cheat meal. Stayed disciplined.', 'Channel celebration energy into the next 25 days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-25 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 26, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Post-milestone momentum is real. No drop-off.', 'Slight overconfidence led to a sloppy diet choice. Caught it early.', 'Stay humble after wins. Discipline does not take days off.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-26 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 27, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'New running route discovered. Outdoor workout was refreshing.', 'Reading felt like a chore today.', 'Switch book genre temporarily if current book loses engagement.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-27 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 28, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Four weeks complete. Staying consistent through monotony is the real win.', 'Boredom with the routine. Everything felt mechanical.', 'Introduce small novelty - new workout music, new walking path.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-28 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 29, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Energy and mood lifted again. Boredom phase passed.', 'Hunger spikes in late evening are becoming a pattern.', 'Shift last meal to 30 minutes later to close the hunger window.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-29 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 30, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 30. Forty percent done. Jeans from two years ago fit again.', 'Hard to believe this is real. Imposter feeling crept in.', 'Track progress objectively - photos and numbers do not lie.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-30 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 31, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Started second month feeling strong and clear-headed.', 'Slight cold symptoms. Pushed through carefully.', 'Hydrate extra and reduce intensity if symptoms worsen.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-01 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 32, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Recovered from cold. Indoor workout kept streak alive.', 'Outdoor workout skipped due to illness caution.', 'Returning to full outdoor routine tomorrow.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-02 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 33, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Full recovery. Back to 100 percent. Both workouts felt great.', 'Lost two days of full output. Had to mentally reset.', 'Health setbacks are not character failures.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-03 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 34, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Crossed the halfway mark to silver. Diet has become instinctive.', 'Skipped a social event to stay on schedule. Felt isolated briefly.', 'Find one way to socialise that fits within the program.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-04 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 35, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Five weeks done. Confidence is up. Posture has improved noticeably.', 'Mild DOMS in legs made running uncomfortable.', 'Add foam rolling session before bed on heavy leg days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-05 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 36, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Personal best on morning run. Fastest 5k yet.', 'Paced too fast early and had to slow down. Need better pacing.', 'Use a running app to pace the first kilometre more conservatively.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-06 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 37, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Reading a chapter that genuinely changed my perspective today.', 'Distracted mind during indoor workout. Only half present.', 'Leave phone outside the workout space.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-07 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 38, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Completed everything even on a low-energy day. That is the point.', 'Energy crash at 3pm. Almost napped through workout window.', 'Schedule workouts for morning when possible.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-08 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 39, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Nearly at 40 days. The compound effect is clearly visible now.', 'Cravings for junk food more intense this week.', 'Identify trigger: stress, boredom, or social cues.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-09 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 40, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 40. Over halfway. Body is completely different from day one.', 'Slight fear of what happens after day 75.', 'Start planning what habits to keep permanently.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-10 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 41, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'New energy source unlocked. Mornings feel purposeful.', 'Slight plateau in visible progress. Frustrating.', 'Plateau is normal. Trust the process and stay consistent.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-11 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 42, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Six weeks complete. Mental toughness is the biggest gain so far.', 'Social pressure from family questioning the diet again.', 'Hold the boundary without over-explaining.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-12 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 43, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Increased weight on indoor workout. Getting stronger.', 'Nothing significant. A smooth day.', 'Keep momentum. Smooth days are a reward for hard ones.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-13 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 44, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Both workouts complete. Water and reading on track.', 'Work lunch provided only non-compliant options. Diet slipped.', 'Pack food for any day with an external lunch commitment.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-14 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 45, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Back fully on track. Three-quarters of the way to silver.', 'Recovering the mindset after a diet slip takes more energy than expected.', 'Process slip quickly and redirect - do not dwell.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-15 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 46, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Best outdoor run of the challenge. Felt completely in flow.', 'Nothing. This was a near-perfect day.', 'Remember this feeling on the hard days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-16 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 47, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Sleep has been consistently excellent for two weeks.', 'Distracted during reading. Re-read the same page three times.', 'Try audiobook on low-focus days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-17 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 48, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Visible abs appearing for the first time. Major motivator.', 'Almost no challenge today. Routine is fully locked in.', 'Push intensity up slightly. Comfort zone is not the growth zone.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-18 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 49, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'One day from silver. Reflecting on the journey so far.', 'Slight anxiety about the final 25 days being harder.', 'Approach day 50 to 75 one day at a time.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-19 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 50, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'SILVER MILESTONE. 50 days. I am not the same person who started this.', 'Emotional moment - almost cried. Had to stay composed.', 'Let the emotion be fuel for the final 25.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-20 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 51, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Post-silver energy is real. Started the final third with fire.', 'Mindset shift required - this is no longer about surviving, it is about finishing strong.', 'Define what a strong finish looks like specifically.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-21 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 52, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Increased reading target voluntarily. Appetite for learning is higher.', 'Harder to surprise myself with progress now. Gains are smaller but real.', 'Measure against day one, not against yesterday.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-22 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 53, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Completed all tasks on a genuinely difficult emotional day.', 'Personal situation outside the challenge caused low mood all day.', 'Separate external circumstances from the challenge identity.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-23 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 54, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Bounce-back after emotional day. Resilience is building.', 'Fatigue from emotional strain carried into workouts.', 'On hard days, intensity is optional but showing up is not.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-24 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 55, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 55. Can see the end. Energy and belief are at a peak.', 'Urge to coast since the end is near. Caught and corrected it.', 'Do not slow down approaching the finish. Finish faster.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-25 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 56, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Eight weeks complete. Discipline is now an identity, not a task.', 'Slight boredom with the same indoor workout structure.', 'Add two new exercises to indoor session for variety.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-26 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 57, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'New indoor exercises added. Workout felt fresh and challenging again.', 'Muscles sore from new movements.', 'Expected DOMS - push through with lower intensity if needed.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-27 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 58, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Diet compliance at an all-time high. No longer a struggle.', 'Nothing meaningful. Day went smoothly.', 'Appreciate the smooth days - they are earned.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-28 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 59, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Almost at 60. Countdown mode activated.', 'Slight impatience to finish. Had to stay present.', 'Finishing is in the daily work. Stay in the day.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-29 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 60, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 60. Eighty percent done. This is the most consistent I have ever been.', 'Hard to imagine going back to old habits. Fear of regression.', 'Plan post-75 maintenance routine now so there is no cliff edge.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-30 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 61, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Final stretch begun. Treating every remaining day as a gift.', 'Weather turned cold - outdoor workout uncomfortable.', 'Invest in cold-weather running gear.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-31 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 62, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Cold weather running is getting easier. Body adapts fast.', 'Slight loneliness - wish I had someone doing this alongside me.', 'Consider joining a 75 Hard community online for the final stretch.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-01 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 63, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Finished the book I was reading. Sense of accomplishment.', 'Choosing the next book took longer than expected.', 'Keep a reading list so the next book is always ready.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-02 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 64, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Started new book. Back in reading flow immediately.', 'Slight overconfidence - cut workout short initially then corrected.', 'Full effort every day. No partial reps this close to the end.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-03 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 65, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Ten days left. Every single task feels meaningful now.', 'Nothing. Pure focus.', 'Carry this clarity into the final ten days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-04 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 66, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Single digits remaining. Emotional and motivated simultaneously.', 'Overthinking the finish line instead of running the current mile.', 'One day at a time. Day 66 is all that matters today.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-05 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 67, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Ran fastest mile of the entire challenge today.', 'Knees slightly sore after the fast run.', 'Ice knees post-run and stretch thoroughly.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-06 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 68, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'One week left. Feeling calm and ready.', 'Urge to already celebrate before finishing. Staying grounded.', 'Celebrate on day 75. Not a day before.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-07 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 69, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'All systems running clean. Diet, workouts, water, reading - all locked in.', 'Nothing. The machine is running well.', 'Trust the machine for the final six days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-08 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 70, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 70. Five left. Gratitude for what this challenge has built.', 'Emotional weight of the end approaching. Hard to articulate.', 'Write down what this challenge has meant before day 75.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-09 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 71, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Wrote reflection notes on the challenge. Clarity on every front.', 'Nothing today. Pure execution.', 'Stay present for the final four days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-10 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 72, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Three days left. The hardest part is not tripping at the finish line.', 'Managed focus well. No stumbles.', 'Identical execution to every other day.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-11 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 73, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Two days left. Surreal. Everything feels heightened.', 'Sleep was lighter than usual due to anticipation.', 'Early bedtime tonight. Finish strong.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-12 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 74, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Final day tomorrow. Ready. Every sacrifice was worth it.', 'Nothing. Absolute focus.', 'Tomorrow: same as every other day. Then celebrate.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-13 22:00:00'),
('a1b2c3d4-e5f6-7890-abcd-ef1234567890', 75, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'GOLD. DAY 75. DONE. 75 Hard complete. I proved to myself I can do anything.', 'Holding back tears during the final run. Could not hold them back after.', 'Build the next chapter with the same discipline that built this one.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-11-14 22:00:00');
INSERT INTO days(user_id, day_number, diet_adhered, outdoor_workout_completed, indoor_workout_completed, water_consumed, pages_read, mood_rating, achievements, challenges, next_day_focus, progress_pic_key, created_at)
VALUES
  ('b2c3d4e5-f6a7-8901-bcde-f12345678901', 1, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Made it through day one. Meal prep paid off. Both workouts done back to back.', 'Indoor workout felt awkward — not sure of my form on some movements.', 'Watch two tutorial videos on form before tomorrows session.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-01 21:30:00'),
('b2c3d4e5-f6a7-8901-bcde-f12345678901', 2, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Outdoor walk was genuinely peaceful. Diet fully clean.', 'Tired from work. Had to drag myself to the second workout.', 'Lay out workout clothes the night before to reduce friction.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-02 21:30:00'),
('b2c3d4e5-f6a7-8901-bcde-f12345678901', 3, TRUE, FALSE, TRUE, TRUE, TRUE, 3, 'Indoor session was strong. Finished reading earlier than expected.', 'Skipped outdoor workout — heavy rain and no backup plan in place yet.', 'Find a covered outdoor route or sheltered space for rainy days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-03 21:30:00'),
('b2c3d4e5-f6a7-8901-bcde-f12345678901', 4, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Best day yet. Energy was high from morning. Ran further than planned.', 'Cravings hit after dinner. Made a compliant snack instead of giving in.', 'Prep compliant snacks in advance so the choice is always easy.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-04 21:30:00'),
('b2c3d4e5-f6a7-8901-bcde-f12345678901', 5, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Five days done. Habit is starting to form. Morning routine feels natural.', 'Social plans almost derailed dinner diet. Stayed on track.', 'Plan what to eat before any social event going forward.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-05 21:30:00');
INSERT INTO days(user_id, day_number, diet_adhered, outdoor_workout_completed, indoor_workout_completed, water_consumed, pages_read, mood_rating, achievements, challenges, next_day_focus, progress_pic_key, created_at)
VALUES
  ('c3d4e5f6-a7b8-9012-cdef-123456789012', 1, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Day one in the books. Woke up early and got the outdoor run done first.', 'Forgot to track water until the afternoon. Had to catch up fast.', 'Set hourly water reminders on phone.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-05 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 2, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Water reminders working well. Hit goal by 5pm.', 'Reading felt slow. Hard to focus after a long day.', 'Read in the morning before work instead.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-06 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 3, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Morning reading was a game changer. Most productive day so far.', 'Almost nothing. Routine clicked into place.', 'Keep morning reading and build on this structure.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-07 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 4, FALSE, TRUE, TRUE, TRUE, TRUE, 3, 'Both workouts done despite a rough diet day. Streak of effort intact.', 'Work lunch had no compliant options. Diet slipped.', 'Pack lunch every day. No exceptions.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-08 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 5, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Packed lunch. Diet fully back on track.', 'Slight guilt from yesterday. Had to let it go and move forward.', 'One slip does not define the journey. Reset and go.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-09 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 6, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'First week almost done. Feeling proud of the consistency.', 'Soreness in legs from running every day. Considered stopping.', 'Slow the outdoor pace — completion matters more than speed right now.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-10 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 7, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'One full week complete. Soreness faded. Body adapting fast.', 'Nothing significant. A clean and smooth day.', 'Carry this energy into week two.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-11 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 8, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Noticed clothes fitting slightly looser. Real motivation boost.', 'Hunger spiked mid-afternoon. Hard to concentrate at work.', 'Add a compliant mid-afternoon snack to the routine.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-12 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 9, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Snack addition worked. Energy stable all day.', 'Almost talked myself out of the indoor workout at 9pm. Pushed through.', 'Move indoor workout earlier in the evening going forward.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-13 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 10, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 10 milestone. Double digits. Feeling genuinely different.', 'Emotional energy — almost cried on the run. Let it happen.', 'Embrace the emotional side of this. It is part of the process.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-14 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 11, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Sleep quality has visibly improved over the past week.', 'Cravings for sugar after dinner. Went for fruit instead.', 'Stock up on compliant sweet alternatives.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-15 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 12, TRUE, TRUE, FALSE, TRUE, TRUE, 3, 'Outdoor workout was the best one yet. Diet perfect.', 'Work emergency meant indoor workout was missed entirely.', 'Block workout time as a non-negotiable calendar event.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-16 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 13, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Recovered from yesterday. Full day back on track.', 'Fatigue from the previous late night still lingering.', 'Protect sleep window — no screens after 10pm.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-17 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 14, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Two full weeks complete. Real physical changes visible in the mirror.', 'Almost nothing. This was one of the best days of the challenge.', 'Use this feeling as fuel when hard days come.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-18 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 15, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Halfway to bronze. Discipline is starting to feel like identity.', 'Boredom with the same meals. Need more variety.', 'Research five new compliant recipes this week.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-19 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 16, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Tried two new recipes. Meals feel exciting again.', 'One recipe did not turn out well. Had to improvise dinner.', 'Always have a backup simple compliant meal ready.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-20 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 17, TRUE, FALSE, TRUE, TRUE, TRUE, 3, 'Indoor workout was particularly strong today. New personal best on squats.', 'Outdoor workout skipped due to severe weather. No covered alternative found.', 'Scout a sheltered outdoor space for weather days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-21 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 18, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Found a covered walkway nearby. Weather backup plan now exists.', 'Mild headache mid-day. Slowed things down but completed everything.', 'Headache was likely dehydration — front-load water intake in the morning.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-22 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 19, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Water front-loading worked. Headache gone. Full energy day.', 'Starting to feel the mental weight of keeping all five tasks up daily.', 'The mental weight is the point. Trust the process.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-23 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 20, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 20. Four-fifths of the way to bronze. Feeling unstoppable.', 'Nothing today. Pure flow state.', 'Replicate todays conditions as closely as possible.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-24 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 21, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Three weeks complete. Routine is fully automatic now. Zero deliberation needed.', 'Slight loneliness — wished I had someone doing this with me.', 'Find an online accountability partner or community.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-25 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 22, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Found a 75 Hard group online. Shared progress. Felt less alone.', 'Comparing progress to others in the group caused a brief dip in confidence.', 'My journey is mine. Stop comparing timelines.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-26 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 23, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Personal best on outdoor run distance. Pushed past the usual turning point.', 'Legs sore after the longer run. Stairs were difficult.', 'Add five minutes of post-run stretching.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-27 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 24, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Stretching added. Legs recovered faster than expected.', 'Anticipation about hitting day 25 made it hard to stay present.', 'Day 24 matters as much as day 25. Stay in today.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-28 21:00:00'),
('c3d4e5f6-a7b8-9012-cdef-123456789012', 25, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'BRONZE MILESTONE. 25 days complete. I am a different person than I was on day one.', 'Wanted to celebrate with food. Chose a long bath and a new book instead.', 'Channel this pride into the next 25 days. The real work starts now.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-29 21:00:00');
INSERT INTO days(user_id, day_number, diet_adhered, outdoor_workout_completed, indoor_workout_completed, water_consumed, pages_read, mood_rating, achievements, challenges, next_day_focus, progress_pic_key, created_at)
VALUES
  ('d4e5f6a7-b8c9-0123-defa-234567890123', 1, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Solid start. Meal prepped on Sunday so day one diet was effortless.', 'Woke up late — had to compress workout timing.', 'Set two alarms and protect the morning window.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-20 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 2, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Both workouts done. Water intake tracked properly for the first time.', 'Energy was low all day. Workouts felt like moving through concrete.', 'Prioritise sleep. Low energy often means poor recovery.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-21 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 3, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Sleep improved. Energy bounced back. Outdoor run was strong.', 'Reading before bed made it harder to wind down.', 'Move reading to the afternoon. Reserve evening for wind-down.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-22 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 4, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Four days straight. Afternoon reading slot is working perfectly.', 'Nothing today. Everything clicked.', 'Stay consistent. Do not change what is working.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-23 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 5, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Five days clean. Week one almost done. Diet has been completely on track.', 'Peer pressure to skip gym and go out. Said no for the first time confidently.', 'Hold that same confidence all week.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-24 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 6, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Declined social plans without guilt. That is growth.', 'Minor tension in right shoulder during indoor workout.', 'Reduce weight on pressing movements until shoulder feels right.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-25 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 7, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'One week done. Shoulder felt fine at reduced weight. Smart call.', 'Nothing significant. A strong clean week.', 'Week two — raise the bar slightly on workout intensity.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-26 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 8, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Increased workout intensity as planned. Felt harder and better.', 'DOMS from the intensity bump made the morning rough.', 'Expected soreness. Work through it gradually.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-27 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 9, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'DOMS fading. Body adapting faster than expected.', 'Restless night — woke up twice. Morning was sluggish.', 'No caffeine after 2pm to protect sleep quality.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-28 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 10, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 10. Double digits. Sleep improved after cutting caffeine. Big milestone energy.', 'Nothing. Best sleep in weeks last night.', 'Protect the caffeine curfew religiously.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-29 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 11, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Ran a personal best distance on the outdoor workout.', 'Ran too fast at the start and had to slow down significantly.', 'Start every run slower. Negative splits are the goal.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-30 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 12, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Paced the run properly. Finished feeling strong rather than wrecked.', 'Diet got boring. Same four meals on rotation.', 'Try a new compliant recipe mid-week.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-08-31 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 13, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'New recipe was genuinely good. Diet variety restored.', 'Almost skipped reading — told myself just one page and ended up reading three chapters.', 'Use the one-page trick whenever motivation to read dips.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-01 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 14, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Two weeks complete. Face looks visibly different. Jaw more defined.', 'Nothing today. Total flow.', 'Two weeks down. Keep the machine running.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-02 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 15, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Halfway to bronze. Routine feels as natural as brushing teeth.', 'Mid-challenge boredom crept in. The novelty has worn off.', 'Boredom is the real test. Boring days build champions.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-03 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 16, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Pushed through the boredom. Showing up without motivation is the skill.', 'Mood was flat all day. No clear reason.', 'Flat days happen. The checklist does not care about mood.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-04 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 17, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Mood lifted by end of day after completing all tasks. The work is the medicine.', 'Slight headache from sun exposure on outdoor run.', 'Wear a cap and apply sunscreen before outdoor workouts.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-05 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 18, TRUE, FALSE, TRUE, TRUE, TRUE, 3, 'Strong indoor workout. Diet perfectly on track.', 'Outdoor workout skipped — family obligation ran all day.', 'Communicate the program to family so they can respect the time blocks.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-06 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 19, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Family understands the schedule now. Outdoor workout back on track.', 'Residual guilt about yesterday. Had to consciously let it go.', 'Guilt is not useful. Action is. Move forward only.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-07 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 20, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 20. Body composition change is very visible now. Strength up across the board.', 'Nothing. One of the cleanest and strongest days of the challenge.', 'Twenty days is proof. The next five take me to bronze.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-08 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 21, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Three weeks complete. The version of me from day one would not recognise this routine.', 'Slight overconfidence — skipped warm-up. Pulled a muscle briefly.', 'Always warm up. No shortcuts on the body.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-09 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 22, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Muscle strain was minor. Full warm-up done. Zero issues.', 'Nothing significant today.', 'Four days to bronze. Stay sharp.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-10 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 23, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Fastest run of the challenge today. Legs feel powerful.', 'Almost nothing. A very clean day.', 'Two days to bronze. Execute.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-11 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 24, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'One day from bronze. Feeling calm, not anxious. Ready.', 'Anticipation made concentration harder during reading.', 'Same execution tomorrow as every other day.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-12 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 25, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'BRONZE MILESTONE. 25 days done. This is the foundation. Now build the house.', 'Temptation to take a rest day as a reward. Stayed disciplined.', 'Bronze is not the prize. Gold is. Stay moving.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-13 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 26, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Post-bronze letdown avoided. Came out stronger on day 26.', 'Slight complacency crept in during indoor workout. Cut one set short.', 'Full effort every set. No partial work.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-14 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 27, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Full effort returned. Best indoor session in a week.', 'Nothing notable. Clean execution.', 'Keep stacking clean days.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-15 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 28, TRUE, TRUE, TRUE, TRUE, TRUE, 3, 'Four weeks complete. Completing the checklist through fatigue is becoming a skill.', 'Week-four fatigue is real. Everything felt heavy today.', 'Recovery is part of the programme. Sleep eight hours tonight.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-16 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 29, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Eight hours of sleep. Fatigue almost completely gone.', 'Hunger was unusually high today.', 'Research whether calories need adjusting given current output levels.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-17 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 30, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 30. Forty percent done. Ran 10k for the first time ever today.', 'Knees slightly tender after the 10k. Iced them immediately.', 'Ice knees post long run as standard practice.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-18 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 31, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Knees fine after icing. Kept todays run shorter as a precaution.', 'Weather turned cold. Outdoor motivation dropped.', 'Cold weather is not an excuse. Dress for it.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-19 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 32, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Bought running jacket. Cold weather running is now fine.', 'Missed a chapter in the reading and had to go back. Concentration slipping.', 'Read with zero distractions — phone in another room.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-20 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 33, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Phone-free reading. Best focus in weeks.', 'Nothing today. Everything executed cleanly.', 'Protect the phone-free reading habit going forward.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-21 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 34, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Well past halfway to silver. Body feels like a machine.', 'Slight ego involvement — started comparing body to others online. Stopped it.', 'Measure against day one self only. No one else.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-22 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 35, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Five weeks done. Strength gains are now obvious to people around me.', 'Compliments from others made me briefly want to coast. Caught it.', 'External validation is not the goal. Internal standard is.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-23 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 36, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Raised indoor workout weights again. Getting objectively stronger.', 'DOMS returned from the weight increase. Expected but uncomfortable.', 'Trust the recovery process. The soreness means growth.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-24 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 37, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'DOMS already fading. Body adapts faster now than it did on day one.', 'Diet was harder to manage at a restaurant. Ordered carefully.', 'Research menus in advance before eating out.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-25 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 38, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Menu research habit starting. Dining out no longer a diet threat.', 'Nothing significant. Smooth execution.', 'Two weeks to silver. Stay the course.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-26 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 39, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Ran with a friend for the first time. Accountability felt different in a good way.', 'Friend ran slower than my pace. Had to hold back.', 'Solo and social runs serve different purposes. Both are valid.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-27 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 40, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Day 40. Eighty percent to silver. This is the most disciplined I have ever been in my life.', 'Hard to believe this is real. Imposter feeling appeared briefly.', 'Look at the log. Forty days of evidence. It is absolutely real.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-28 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 41, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Reviewed the log as planned. The evidence is undeniable. Confidence restored.', 'Nothing today. The log review recentred everything.', 'Review progress weekly going forward.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-29 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 42, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Six weeks complete. Habit stack is completely automatic. Zero effort to initiate tasks.', 'Slight plateau in visible body composition changes. Frustrating.', 'Plateaus are adaptation. They precede the next jump. Stay patient.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-09-30 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 43, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Accepted the plateau mentally. Focused on execution, not results.', 'Nothing significant today.', 'Eight days to silver. One day at a time.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-01 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 44, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'Plateau broke. Noticeable change in physique overnight. Patience paid off.', 'Nothing today. The body rewarded the patience.', 'This is what trusting the process looks like.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-02 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 45, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Three-quarters of the way to silver. Momentum is at an all-time high.', 'Urge to add more tasks to the challenge. Resisted adding scope.', 'Finish what I started. Additions after day 75.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-03 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 46, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Smoothest day of the challenge so far. No friction anywhere.', 'Nothing. Absolutely nothing.', 'Four days to silver. Same as every other day.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-04 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 47, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Finished the second book of the challenge. Reading speed has increased dramatically.', 'Starting a new book mid-challenge felt disruptive briefly.', 'Always have the next book chosen before finishing the current one.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-05 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 48, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'New book is excellent. Reading motivation at its highest.', 'Minor cold starting. Reduced intensity but completed everything.', 'Rest more tonight. Full intensity when fully healthy.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-06 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 49, TRUE, TRUE, TRUE, TRUE, TRUE, 4, 'Cold fading fast. Body recovering quicker than it used to. Fitness is protective.', 'One day from silver. Trying to stay emotionally level.', 'Silver is a milestone, not the destination. Keep the head level.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-07 21:00:00'),
('d4e5f6a7-b8c9-0123-defa-234567890123', 50, TRUE, TRUE, TRUE, TRUE, TRUE, 5, 'SILVER MILESTONE. 50 days complete. Halfway. I am proof that this is possible.', 'Emotional on the run. Had to stop and breathe for a moment.', 'The final 25 days are where legends are made. Start them tomorrow.', '1a82407e-18fb-4443-9515-c72451d361c3/11a86349-b829-44ba-82e8-8fbb7b2287ec.jpg', '2024-10-08 21:00:00');
